import os, sys, hashlib
from collections import defaultdict

base = '/volume1/mac/Decor/Generic Decor'
olds = ['/volume1/mac/Decor/Generic Decor.old', '/volume1/mac/Decor/Generic Kids.old']

def rel(root, path):
    return os.path.relpath(path, root).replace(os.sep, '/')

def walk_files(root):
    out = []
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames.sort(key=str.lower)
        filenames.sort(key=str.lower)
        for name in filenames:
            full = os.path.join(dirpath, name)
            try:
                st = os.stat(full)
            except OSError as e:
                out.append({'rel': rel(root, full), 'full': full, 'error': str(e)})
                continue
            out.append({'rel': rel(root, full), 'full': full, 'size': st.st_size, 'mtime': int(st.st_mtime)})
    return out

def walk_dirs(root):
    out = []
    for dirpath, dirnames, filenames in os.walk(root):
        dirnames.sort(key=str.lower)
        for name in dirnames:
            out.append(rel(root, os.path.join(dirpath, name)))
    return out

def sha256(path):
    h = hashlib.sha256()
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(1024 * 1024), b''):
            h.update(chunk)
    return h.hexdigest()

base_files = walk_files(base)
base_dirs = walk_dirs(base)
base_rel = {x['rel'].casefold(): x for x in base_files if 'error' not in x}
base_dir_rel = {x.casefold(): x for x in base_dirs}
all_missing = {}
all_missing_dirs = {}

for old in olds:
    old_files = walk_files(old)
    old_dirs = walk_dirs(old)
    missing = [x for x in old_files if x.get('rel','').casefold() not in base_rel]
    missing_dirs = [x for x in old_dirs if x.casefold() not in base_dir_rel]
    all_missing[old] = (old_files, missing)
    all_missing_dirs[old] = (old_dirs, missing_dirs)

sizes_needed = {x['size'] for _, missing in all_missing.values() for x in missing if 'size' in x}
base_hashes_by_size = defaultdict(set)
base_paths_by_size_hash = defaultdict(list)
if sizes_needed:
    for x in base_files:
        if 'error' in x or x.get('size') not in sizes_needed:
            continue
        try:
            digest = sha256(x['full'])
        except OSError as e:
            continue
        base_hashes_by_size[x['size']].add(digest)
        base_paths_by_size_hash[(x['size'], digest)].append(x['rel'])

print('Synology Decor recursive comparison', flush=True)
print('Base: ' + base, flush=True)
print('Compared old folders against the base by same relative path and by content hash anywhere in the base tree.', flush=True)
print('', flush=True)
print('SUMMARY', flush=True)
print(f'Base files: {len(base_files)}', flush=True)
print(f'Base directories: {len(base_dirs)}', flush=True)

summary_lines = []
for old in olds:
    old_files, missing = all_missing[old]
    old_dirs, missing_dirs = all_missing_dirs[old]
    content_missing = []
    content_present_elsewhere = []
    for x in missing:
        if 'error' in x:
            content_missing.append((x, None, []))
            continue
        try:
            digest = sha256(x['full'])
        except OSError as e:
            y = dict(x); y['error'] = str(e)
            content_missing.append((y, None, []))
            continue
        matches = base_paths_by_size_hash.get((x['size'], digest), [])
        if matches:
            content_present_elsewhere.append((x, digest, matches))
        else:
            content_missing.append((x, digest, []))

    summary_lines.append((old, len(old_files), len(old_dirs), len(missing), len(missing_dirs), len(content_missing), len(content_present_elsewhere)))
    print('', flush=True)
    print('OLD FOLDER: ' + old, flush=True)
    print(f'Files in old folder: {len(old_files)}', flush=True)
    print(f'Directories in old folder: {len(old_dirs)}', flush=True)
    print(f'Files missing by same relative path: {len(missing)}', flush=True)
    print(f'Directories missing by same relative path: {len(missing_dirs)}', flush=True)
    print(f'Files whose content was NOT found anywhere in base: {len(content_missing)}', flush=True)
    print(f'Files missing at that path but content exists elsewhere in base: {len(content_present_elsewhere)}', flush=True)

    print('', flush=True)
    print('FILES WITH CONTENT NOT FOUND ANYWHERE IN BASE', flush=True)
    if not content_missing:
        print('(none)', flush=True)
    for x, digest, matches in sorted(content_missing, key=lambda t: t[0].get('rel','').casefold()):
        err = (' ERROR=' + x.get('error')) if x.get('error') else ''
        print(f"{x.get('rel')}\t{x.get('size','?')} bytes\t{x.get('full')}{err}", flush=True)

    print('', flush=True)
    print('FILES MISSING AT SAME RELATIVE PATH BUT SAME CONTENT FOUND ELSEWHERE IN BASE', flush=True)
    if not content_present_elsewhere:
        print('(none)', flush=True)
    for x, digest, matches in sorted(content_present_elsewhere, key=lambda t: t[0].get('rel','').casefold()):
        shown = '; '.join(matches[:10])
        more = '' if len(matches) <= 10 else f'; ... +{len(matches)-10} more'
        print(f"{x['rel']}\t{x['size']} bytes\told={x['full']}\tbase_match={shown}{more}", flush=True)

    print('', flush=True)
    print('DIRECTORIES MISSING BY SAME RELATIVE PATH', flush=True)
    if not missing_dirs:
        print('(none)', flush=True)
    for d in sorted(missing_dirs, key=str.casefold):
        print(d, flush=True)

print('', file=sys.stderr)
print('SUMMARY:', file=sys.stderr)
print(f'Base files: {len(base_files)}; base directories: {len(base_dirs)}', file=sys.stderr)
for old, old_count, old_dir_count, missing_count, missing_dir_count, content_missing_count, moved_count in summary_lines:
    print(f'{old}: files={old_count}, dirs={old_dir_count}, missing_same_path={missing_count}, missing_dirs={missing_dir_count}, content_not_in_base={content_missing_count}, content_elsewhere_in_base={moved_count}', file=sys.stderr)
